import React from "react";
import CardTxtComp from "./CardTextComp";
import CardPhotoComp from "./CardPhotoComp";
import { CardType } from "../utils/EnumData";

export default function CardSelector(props) {
  let { cardType, displayCardImage } = props;

  return (
    <>
      {cardType === CardType.TXT ? <CardTxtComp {...props} /> : <></>}
      {cardType === CardType.IMGTXT ? (
        displayCardImage ? (
          <CardPhotoComp {...props} />
        ) : (
          <CardTxtComp {...props} />
        )
      ) : (
        <></>
      )}
    </>
  );
}
