//import "./App.css";
import React from "react";
import axios from "axios";
import { createTheme, ThemeProvider, styled } from "@mui/material/styles";
import { CssBaseline } from "@mui/material";

import CardSelector from "./components/CardSelector";
import FABComp from "./components/FABComp";
import CopyrightComp from "./components/CopyrightComp";

import { sleep } from "./utils/Utils";
import { Lowercase, Uppercase, Numbers } from "./utils/DataUtils";
import { CardType } from "./utils/EnumData";

// eslint-disable-next-line
const darkTheme = createTheme({ palette: { mode: "dark" } });
// eslint-disable-next-line
const lightTheme = createTheme({ palette: { mode: "light" } });

const MainArea = styled("div")(({ theme }) => ({
  ...theme.typography.body2,
  textAlign: "center",
  //minHeight: "100vh", // before rotate
  height: "100vmin",
  width: "100vmax",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
  justifyContent: "center",
  //WebkitTransform: "rotate(90deg)",
  backgroundColor: theme.palette.background.default,
}));

const defaultMenuOpt = ["Number", "Lowercase", "Uppercase"];

let isDev = true;
if (!process.env.NODE_ENV || process.env.NODE_ENV === "development") {
  isDev = true;
} else {
  isDev = false;
}

function App() {
  //Card Type: EnumData.CardType
  const [cardType, setCardType] = React.useState(CardType.TXT);
  //Menu option: which one user click
  const [wordType, setWordType] = React.useState("Number");
  //Words for display
  const [wordDataArray, setWordDataArray] = React.useState([]);
  //Which one to display in Words Array
  const [cardInner, setCardInner] = React.useState(0);
  //Set random to display word
  const [rand, setRand] = React.useState(false);
  //Set show image button or not
  const [showImgBtn, setShowImgBtn] = React.useState(false);
  //Set show Card image or not
  const [displayCardImage, setDisplayCardImage] = React.useState(false);
  //Init the Menu options
  const [menuOpt, setMenuOpt] = React.useState(defaultMenuOpt);
  //從外部取得學習數據
  const [extWordData, setExtWordData] = React.useState({});

  //每張閱讀咭所需的資訊
  const CardPara = {
    cardType: cardType, //For selector
    wordDataArray: wordDataArray,
    cardInner: cardInner,
    displayCardImage: displayCardImage,
  };

  //FAB資訊
  const FABPara = {
    menuOpt: menuOpt,
    wordType: wordType,
    setWordType: setWordType,
    cardInner: cardInner,
    setCardInner: setCardInner,
    rand: rand,
    setRand: setRand,
    displayCardImage: displayCardImage,
    setDisplayCardImage: setDisplayCardImage,
    wordsLen: wordDataArray.length,
    showWordTypeMenu: true,
    showRandBtn: true,
    showImgBtn: showImgBtn,
  };

  //從外部取得學習數據
  React.useEffect(() => {
    const fetchWords = () => {
      axios({
        method: "get",
        url: "https://script.google.com/macros/s/AKfycbwt8q-ePNiRFIYcw4lUXOeL1YgVHpslJg8ChXnSxC477aJs1dn3r0_L__Zx2GhJS95rvA/exec",
      }).then((res) => {
        let extWordJson = parseExtWordData(res);
        setExtWordData(extWordJson);

        //在Menu上添加選項
        let extMenuOpt = [];
        for (let key in extWordJson) {
          extMenuOpt.push(key);
        }
        setMenuOpt(defaultMenuOpt.concat(extMenuOpt));
      });
    };

    var parseExtWordData = (extJSON) => {
      let resultData = {};
      let jsonData = extJSON.data;
      for (var key in jsonData) {
        if (isDev || jsonData[key].Valid === true) {
          let jsonKey = jsonData[key].Title;

          let dataV1 = {};
          dataV1[jsonKey] = jsonData[key].Words;

          let dataV2 = {};
          let subData1 = { Words: jsonData[key].Words };
          let subData2 = { CardType: jsonData[key].CardType };
          let subData3 = { ImgLinks: jsonData[key].ImgLinks };
          dataV2[jsonKey] = Object.assign(subData1, subData2, subData3);
          Object.assign(resultData, dataV2);
        }
      }
      return resultData;
    };

    fetchWords();
  }, []);

  //處理WordType改變
  React.useEffect(() => {
    let cardType = CardType.TXT;
    let wordArray;
    let imgLinksArray;
    let dataArray = [];

    if (wordType === "Uppercase") wordArray = Uppercase.slice();
    else if (wordType === "Lowercase") wordArray = Lowercase.slice();
    else if (wordType === "Number") wordArray = Numbers.slice();
    else {
      //dataArrayTmp = extWordData[wordType].slice(); //For parseExtWordData: dataV1
      wordArray = extWordData[wordType].Words.slice();
      cardType = extWordData[wordType].CardType;
    }

    if (cardType === CardType.TXT) setShowImgBtn(false);
    if (cardType === CardType.IMGTXT) {
      imgLinksArray = extWordData[wordType].ImgLinks;
      if (imgLinksArray !== undefined) {
        setShowImgBtn(true);
        setDisplayCardImage(true);
      }
    }
    setCardType(cardType);

    //Combind Data
    for (let i = 0; i < wordArray.length; i++) {
      let res = {};
      Object.assign(res, { word: wordArray[i] });
      if (imgLinksArray !== undefined) {
        Object.assign(res, { imgLink: imgLinksArray[i] });
      }
      //if (soundLinks........)
      dataArray.push(res);
    }

    if (rand) {
      //v1
      //wordArray = wordArray.sort(() => Math.random() - 0.5);

      //v2
      dataArray = dataArray.sort(() => Math.random() - 0.5);
    }

    setWordDataArray(dataArray);
    return () => {};
  }, [cardType, wordType, rand, extWordData]);

  /*
  React.useEffect(() => {
    let dataArrayTmp = wordDataArray;
    if (rand) {
      dataArrayTmp = dataArrayTmp.sort(() => Math.random() - 0.5);
    }
    setWordDataArray(dataArrayTmp);
    return () => {};
  }, [rand]);
  */
  const isLandscape = () =>
    window.matchMedia("(orientation:landscape)").matches;

  const [orientation, setOrientation] = React.useState(
    isLandscape() ? "landscape" : "portrait"
  );

  /* 處理直向橫向問題 */
  React.useEffect(() => {
    //console.log("effect: " + orientation);
  }, [orientation]);

  React.useEffect(() => {
    window.onorientationchange = () => {
      sleep(50).then((r) => {
        let isLand = isLandscape() ? "landscape" : "portrait";
        setOrientation(isLand);
      });
    };
  });
  //sx={{ WebkitTransform: "rotate(0deg)" }}
  // return (
  //   <ThemeProvider theme={darkTheme}>
  //     <CssBaseline />
  //     <FABComp {...FABPara} />
  //     <CssBaseline />
  //     <CopyrightComp />
  //   </ThemeProvider>
  // );
  //position: absolute; left: 1px; top: 50%; -ms-transform: translateY(-50%); -webkit-transform: translateY(-50%); -moz-transform: translateY(-50%); -o-transform: translateY(-50%); transform: translateY(-50%);
  const rotateStyle = {
    WebkitTransform: "scale(0.9,0.9) rotate(90deg)" /* Safari and Chrome */,
    transform: "scale(1,) rotate(90deg)" /* Firefox, IE 9, Opera */,
    position: "absolute",
    left: "-50%",
    top: "25%",
  };

  return (
    <div style={orientation === "landscape" ? {} : rotateStyle}>
      <ThemeProvider theme={darkTheme}>
        <CssBaseline />
        <MainArea>
          <FABComp {...FABPara} />
          <CardSelector {...CardPara} />
        </MainArea>
        <CssBaseline />
        {/*}
          <MainArea>
            <Typography
              style={{ WebkitWritingMode: "vertical-rl", fontSize: "6vh" }}
            >
              請橫置你的設備 <br />
              Please rotate your device
            </Typography>
          </MainArea>
          */}
        <CopyrightComp />
      </ThemeProvider>
    </div>
  );
}

export default App;
