import * as React from "react";
import { styled } from "@mui/material/styles";
import IconButton from "@mui/material/IconButton";
import Menu from "@mui/material/Menu";
import MenuItem from "@mui/material/MenuItem";
import DehazeIcon from "@mui/icons-material/Dehaze";
import Button from "@mui/material/Button";
import Box from "@mui/material/Box";

import ArrowBackIosNewIcon from "@mui/icons-material/ArrowBackIosNew";
import ArrowForwardIosIcon from "@mui/icons-material/ArrowForwardIos";

//Show Letter Opt
//const options = ["Number", "Lowercase", "Uppercase", "Words"];

const ITEM_HEIGHT = 48;

const WordsTypeFAB = styled(IconButton)(({ theme }) => ({
  margin: theme.spacing(1),
  position: "fixed",
  left: theme.spacing(1),
  top: theme.spacing(1),
}));

const TopFABArea = styled(Box)(({ theme }) => ({
  ...theme.typography.body2,
  margin: theme.spacing(1),
  position: "fixed",
  display: "flex",
  fontSize: "small",
  justifyContent: "space-between",
  alignItems: "center",
  top: theme.spacing(1),
}));

const RandomBtn = styled(Button)(({ theme }) => ({
  ...theme.typography.body2,
  margin: theme.spacing(0, 0.5),
  fontSize: "small",
}));

const ImageBtn = styled(Button)(({ theme }) => ({
  ...theme.typography.body2,
  margin: theme.spacing(0, 0.5),
  fontSize: "small",
}));

const ArrowBtn = styled(Button)(({ theme }) => ({
  ...theme.typography.body2,
  //backgroundColor: theme.palette.background.default,
  fontSize: "6rem",
  margin: theme.spacing(0),
  padding: theme.spacing(0),
  position: "fixed",
  //right: theme.spacing(1),
}));

export default function FABMenu(props) {
  /* For Word Type Menu */
  let { menuOpt, wordType, setWordType, setCardInner, showWordTypeMenu } =
    props;
  const [anchorEl, setAnchorEl] = React.useState(null);
  const open = Boolean(anchorEl);
  const handleClick = (event) => {
    setAnchorEl(event.currentTarget);
  };
  const handleClose = () => {
    setAnchorEl(null);
  };
  const setMenuWordType = (type) => {
    setWordType(type);
    setCardInner(0);
    handleClose();
  };

  /* For Random Button */
  let { rand, setRand, cardInner, showRandBtn } = props;

  /* For Arrow Button */
  let { wordsLen } = props;

  var changeCardInner = (cardInner, direction) => {
    let diff = direction === "N" ? +1 : -1;
    let output = cardInner + diff;
    return output;
  };

  /* For Display Image Button */
  let { showImgBtn, displayCardImage, setDisplayCardImage } = props;

  return (
    <>
      {showWordTypeMenu ? (
        <WordsTypeFAB
          aria-label="more"
          id="long-button"
          aria-controls="long-menu"
          aria-expanded={open ? "true" : undefined}
          aria-haspopup="true"
          onClick={handleClick}
        >
          <DehazeIcon />
        </WordsTypeFAB>
      ) : (
        <></>
      )}
      {showWordTypeMenu ? (
        <Menu
          id="long-menu"
          MenuListProps={{
            "aria-labelledby": "long-button",
          }}
          anchorEl={anchorEl}
          open={open}
          onClose={handleClose}
          PaperProps={{
            style: {
              maxHeight: ITEM_HEIGHT * 4.5,
              width: "20ch",
            },
          }}
        >
          {menuOpt.map((option) => (
            <MenuItem
              key={option}
              selected={option === wordType}
              onClick={() => setMenuWordType(option)}
            >
              {option}
            </MenuItem>
          ))}
        </Menu>
      ) : (
        <></>
      )}
      <TopFABArea>
        {showRandBtn ? (
          <RandomBtn
            variant={rand ? "contained" : "outlined"}
            onClick={() => {
              setRand(!rand);
              setCardInner(0);
            }}
          >
            Random
          </RandomBtn>
        ) : (
          <></>
        )}
        {showImgBtn ? (
          <ImageBtn
            variant={displayCardImage ? "contained" : "outlined"}
            onClick={() => {
              setDisplayCardImage(!displayCardImage);
            }}
          >
            Image
          </ImageBtn>
        ) : (
          <></>
        )}
      </TopFABArea>
      {true ? (
        <>
          <ArrowBtn
            onClick={() => setCardInner(changeCardInner(cardInner, "P"))}
            disabled={cardInner === 0}
            sx={{ left: "0px" }}
          >
            <ArrowBackIosNewIcon fontSize="inherit" />
          </ArrowBtn>
          <ArrowBtn
            onClick={() => setCardInner(changeCardInner(cardInner, "N"))}
            disabled={cardInner === wordsLen - 1}
            sx={{ right: "0px" }}
          >
            <ArrowForwardIosIcon fontSize="inherit" />
          </ArrowBtn>
        </>
      ) : (
        <></>
      )}
    </>
  );
}
